const now = new Date();
const tomorrow = new Date(now);
tomorrow.setDate(now.getDate() + 1);
// Only proceed if tomorrow is the 1st (i.e., today is last day of month)
if (tomorrow.getDate() !== 1) {
  return []; // Stop execution
}
return [{ json: { month: now.toLocaleString('en', { month: 'long' }), year: now.getFullYear() } }];

const client = items[0].json;
const tier = client['Tier'] || 'T1';
const budgets = { 'T1': 4, 'T2': 10, 'T3': 22 };
const ceilings = { 'T1': 5.5, 'T2': 13, 'T3': 27 };
const budget = budgets[tier] || 4;
const ceiling = ceilings[tier] || 5.5;
const actual = parseFloat(client['Hours This Month'] || 0);
const pct = budget > 0 ? Math.round((actual / budget) * 100) : 0;
items[0].json.hoursBudget = budget;
items[0].json.hoursCeiling = ceiling;
items[0].json.hoursActual = actual;
items[0].json.hoursPercent = pct;
items[0].json.overBudget = actual > budget;
items[0].json.overCeiling = actual > ceiling;
items[0].json.flag = actual > budget * 1.1; // Flag at 110% of budget
return items;
